parameters.jsCode:
// Parse the AI response and build the final payload
const aiResponse = $input.first().json.message.content;

let parsed;
try {
  // Remove markdown code blocks if present
  const clean = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message + '\nRaw: ' + aiResponse);
}

const webhookData = $('Webhook Trigger').first().json;

return [{
  json: {
    meeting_title: parsed.meeting_title || webhookData.meeting_title || 'Reunión sin título',
    meeting_date: webhookData.meeting_date || new Date().toISOString().slice(0, 10),
    transcript: webhookData.transcript || '',
    tasks: parsed.tasks || []
  }
}];
